module top_module(
    input [3:0] in,
    input [1:0] control,
    output reg [3:0] shifted_out
);always @(*) begin
    case (control)
        2'b00: shifted_out = in << 1;
        2'b01: shifted_out = in << 2;
        2'b10: shifted_out = in >> 1;
        2'b11: shifted_out = in >> 2;
    endcase
end

endmodule
